// Basic comparator patterns
const byNumber = (a: number, b: number) => a - b;
const byString = (a: string, b: string) => a.localeCompare(b);
const byDate = (a: Date, b: Date) => a.getTime() - b.getTime();

// Sort objects by property
function sortBy<T>(items: T[], key: keyof T, dir: 'asc' | 'desc' = 'asc'): T[] {
  return [...items].sort((a, b) => {
    const av = a[key], bv = b[key];
    const cmp = av < bv ? -1 : av > bv ? 1 : 0;
    return dir === 'asc' ? cmp : -cmp;
  });
}

// Multi-key sort
type SortKey<T> = { key: keyof T; dir?: 'asc' | 'desc' };
function multiSort<T>(items: T[], keys: SortKey<T>[]): T[] {
  return [...items].sort((a, b) => {
    for (const { key, dir = 'asc' } of keys) {
      const av = a[key], bv = b[key];
      const cmp = av < bv ? -1 : av > bv ? 1 : 0;
      if (cmp !== 0) return dir === 'asc' ? cmp : -cmp;
    }
    return 0;
  });
}

// Schwartzian transform for expensive key extraction
function sortByExpensiveKey<T>(items: T[], getKey: (item: T) => number): T[] {
  return items
    .map((item) => ({ item, key: getKey(item) }))
    .sort((a, b) => a.key - b.key)
    .map(({ item }) => item);
}

