function useSortedData<T extends Record<string,unknown>>(data: T[]) {
  const [sort, setSort] = React.useState<{key: keyof T, dir:'asc'|'desc'}|null>(null);
  const sorted = React.useMemo(() => {
    if (!sort) return data;
    return [...data].sort((a,b) => {
      const av = a[sort.key], bv = b[sort.key];
      const cmp = av < bv ? -1 : av > bv ? 1 : 0;
      return sort.dir === 'asc' ? cmp : -cmp;
    });
  }, [data, sort]);
  const toggleSort = (key: keyof T) => setSort(s =>
    s?.key === key ? { key, dir: s.dir==='asc'?'desc':'asc' } : { key, dir: 'asc' }
  );
  return { sorted, sort, toggleSort };
}

// Simple O(n log n) — fine for most frontend cases
function topK<T>(items: T[], score: (item: T) => number, k: number): T[] {
  return [...items]
    .sort((a, b) => score(b) - score(a))
    .slice(0, k);
}
